INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (321, 1, 24001, 0, 125801, 2, "リリ", 1, 40011, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n");
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (322, 1, 24001, 0, 126001, 2, "クリア", 2, 40011, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます");
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (323, 1, 24001, 0, 126101, 2, "プレシア", 3, 40011, 1, "んーと。\nこれ、あげる。\nはい");
