INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (325, 2, 24001, 0, 126001, 2, "クリア", 5, 40011, 1, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです");
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (326, 2, 24001, 0, 126101, 2, "プレシア", 6, 40011, 1, "お兄。\nきてくれて、うれしい");
